#[derive(Clone, Copy, PartialEq, Eq, Debug, serde::Serialize, serde::Deserialize)]
pub enum Method {
    Get,
    Post,
    Put,
    Patch,
    Delete,
    Head,
    Options,
    Connect,
    Trace,
}

impl Default for Method {
    fn default() -> Self {
        Self::Get
    }
}

impl magnus::IntoValue for Method {
    fn into_value_with(self, handle: &Ruby) -> magnus::Value {
        let sym = match self {
            Method::Get => "get",
            Method::Post => "post",
            Method::Put => "put",
            Method::Patch => "patch",
            Method::Delete => "delete",
            Method::Head => "head",
            Method::Options => "options",
            Method::Connect => "connect",
            Method::Trace => "trace",
        };
        handle.to_symbol(sym).into_value_with(handle)
    }
}

impl magnus::TryConvert for Method {
    fn try_convert(val: magnus::Value) -> Result<Self, magnus::Error> {
        let s: String = magnus::TryConvert::try_convert(val)?;
        // Accept the serde wire name (snake_case), the PascalCase Rust variant name,
        // and a lowercase fallback so fixtures written in any of those styles work.
        match s.as_str() {
            "get" | "Get" => Ok(Method::Get),
            "post" | "Post" => Ok(Method::Post),
            "put" | "Put" => Ok(Method::Put),
            "patch" | "Patch" => Ok(Method::Patch),
            "delete" | "Delete" => Ok(Method::Delete),
            "head" | "Head" => Ok(Method::Head),
            "options" | "Options" => Ok(Method::Options),
            "connect" | "Connect" => Ok(Method::Connect),
            "trace" | "Trace" => Ok(Method::Trace),
            other => Err(magnus::Error::new(
                unsafe { Ruby::get_unchecked() }.exception_arg_error(),
                format!("invalid Method value: {other}"),
            )),
        }
    }
}

unsafe impl IntoValueFromNative for Method {}
unsafe impl TryConvertOwned for Method {}

