/// Convert a `spikard::AppError` error to a Magnus runtime error.
#[allow(dead_code)]
fn app_error_to_magnus_err(e: spikard::AppError) -> magnus::Error {
    let msg = e.to_string();
    magnus::Error::new(unsafe { magnus::Ruby::get_unchecked() }.exception_runtime_error(), msg)
}

